-- 1. Sittingbourne × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'sittingbourne',
  'Sittingbourne is a working town with serious commercial momentum. With a population of around 63,000 and substantial residential growth, the town is attracting new businesses alongside the established industrial and trades sector that has long been its backbone. When a homeowner in one of the new housing developments searches for a local electrician, or a logistics company at Eurolink Industrial Estate needs a supplier, they judge your business by your website within seconds. The problem is that many Sittingbourne businesses still operate with websites that were built cheaply years ago, failing to reflect the quality of service they actually deliver. We build modern, conversion-focused websites for Sittingbourne businesses that load fast, work flawlessly on mobile, and turn the growing volume of local search traffic into genuine enquiries and paying customers.',
  'Sittingbourne sits at the heart of Swale Borough, connected to the M2 and M20 via the A249, making it a strategic location for logistics, distribution, and trades businesses covering wider Kent. The Forum shopping centre anchors the town centre retail, while Eurolink Industrial Estate and surrounding business parks host a concentration of commercial operations. Milton Creek Country Park provides a green corridor through the town, and the Sittingbourne and Kemsley Light Railway draws heritage visitors. The town''s brickmaking heritage has given way to a more diverse economy, with significant residential growth creating fresh demand for local services.',
  'The web design market in Sittingbourne is dominated by budget providers and DIY website builders. Many businesses, particularly trades and industrial firms around Eurolink, treat their website as an afterthought rather than a sales tool. This creates an immediate opportunity for businesses willing to invest in a professional digital presence. The gap between businesses with modern, mobile-optimised sites and those with outdated pages is starkly visible and directly impacts who captures the growing number of local searches.',
  'Our approach for Sittingbourne clients focuses on practical, results-driven web design. We understand that trades, industrial firms, and service businesses here need sites that generate phone calls and quote requests, not design awards. Every Sittingbourne site we build is optimised for the local search terms that drive real business, loads under two seconds on mobile, and includes clear conversion paths that make it easy for potential customers to get in touch.',
  '{"population": 63000, "borough": "Swale", "transport": "A249 connecting M2/M20", "business_districts": ["Eurolink Industrial Estate", "The Forum", "High Street", "Milton Creek area"], "key_fact": "Strategic logistics hub with strong trades sector and significant residential growth"}',
  '[{"title": "Cheap websites costing Sittingbourne businesses real money", "description": "A budget website that looked acceptable five years ago now drives customers away. When Sittingbourne residents compare your outdated site against a competitor with a clean, modern design, they choose the competitor every time. The money saved on a cheap website is lost many times over in missed enquiries."}, {"title": "No mobile optimisation for on-the-go Sittingbourne searches", "description": "Tradespeople, drivers, and busy homeowners in Sittingbourne search on their phones. A website that does not display properly on mobile, loads slowly, or makes it difficult to tap a phone number loses the enquiry instantly. Over sixty percent of local searches happen on mobile devices."}, {"title": "Industrial and trade sites invisible in Sittingbourne searches", "description": "Businesses at Eurolink Industrial Estate and surrounding commercial areas often have minimal online presence. When procurement managers or new customers search for suppliers, these businesses do not appear. Competitors with better websites capture the contracts that should be theirs."}]',
  '[{"title": "Results-focused websites for Sittingbourne businesses", "description": "We build websites engineered to generate enquiries. Clear phone numbers, prominent quote request forms, fast mobile loading, and content optimised for how Sittingbourne customers actually search. No unnecessary complexity, just effective design that turns visitors into customers."}, {"title": "Mobile-first design for Sittingbourne''s on-the-go searchers", "description": "Every Sittingbourne site is built mobile-first, ensuring fast loading and effortless navigation on phones and tablets. Click-to-call buttons, thumb-friendly forms, and compressed images mean your site works perfectly for the tradesperson checking your services between jobs or the homeowner searching from the sofa."}, {"title": "Trade and industrial web presence for Eurolink businesses", "description": "We build professional websites for Sittingbourne''s commercial and industrial sector that showcase capabilities, service areas, and credentials effectively. From logistics firms to specialist manufacturers, your website becomes a genuine business development tool rather than a neglected digital placeholder."}]',
  '[{"question": "How much does a new website cost for a Sittingbourne business?", "answer": "Our Sittingbourne websites start from a level that reflects the practical, results-driven approach the local market needs. We offer fixed-price packages so you know exactly what you are paying. Every site includes mobile optimisation, basic SEO setup, and conversion-focused design as standard."}, {"question": "How long does a Sittingbourne website project take?", "answer": "Most Sittingbourne sites launch within three to five weeks. We work efficiently because we understand that businesses here need results quickly. Trades and service businesses can often go live even faster when they have their content and images ready at the start of the project."}, {"question": "Will my website rank for Sittingbourne searches?", "answer": "Every site includes foundational SEO with Sittingbourne-specific page titles, descriptions, and content structure. This gives you a strong starting position for local search terms. For businesses wanting to dominate Sittingbourne search results, we offer dedicated SEO campaigns that build on this foundation."}, {"question": "Can you redesign my existing Sittingbourne business website?", "answer": "Yes. We redesign existing sites regularly, preserving any search authority your current site has built while delivering a modern, conversion-focused design. We handle all technical migration including redirects, so you do not lose any existing Google rankings during the transition."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
