-- 6. Sittingbourne × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'sittingbourne',
  'Social media is where Sittingbourne residents go for recommendations. The town has active Facebook community groups where thousands of members regularly ask for tradesperson recommendations, restaurant suggestions, and service providers. A business with a professional, active social media presence gets tagged in these conversations. A business with no presence or an outdated profile does not exist in this crucial word-of-mouth channel. Beyond community groups, Instagram increasingly drives decisions for hospitality and retail businesses near The Forum, while LinkedIn connects the commercial firms at Eurolink with suppliers and partners. We set up and optimise social media profiles for Sittingbourne businesses so they look professional, appear in the right conversations, and convert social browsers into paying customers.',
  'Sittingbourne''s social media landscape is dominated by Facebook community groups where residents actively seek recommendations and share experiences. These groups function as a digital word-of-mouth network that can make or break local businesses. Instagram is growing for the town''s food, drink, and retail sectors, with Milton Creek Country Park and the heritage railway providing photogenic local content hooks. LinkedIn serves the Eurolink business community and professional services. The practical, community-oriented demographic engages most with useful, authentic content rather than polished corporate messaging.',
  'Social media quality among Sittingbourne businesses is mixed. Some trades have built strong followings through active community group engagement, while many others have abandoned or incomplete profiles. Retail businesses near The Forum vary from active Instagram users to those with no social presence at all. The opportunity lies in professional setup combined with authentic local engagement, particularly within the community groups where recommendations directly generate business.',
  'Our social media setup for Sittingbourne focuses on the platforms that actually drive business here. Facebook is non-negotiable for most Sittingbourne businesses because of the active community groups. We set up profiles optimised for group engagement and local search, create branded visual assets, and develop a content strategy that positions your business as the natural recommendation when Sittingbourne residents ask for help.',
  '{"population": 63000, "borough": "Swale", "business_districts": ["Eurolink Industrial Estate", "The Forum", "High Street"], "key_fact": "Active Facebook community groups function as a primary recommendation channel for local businesses"}',
  '[{"title": "Missing from Sittingbourne community group recommendations", "description": "When a Sittingbourne resident posts asking for a plumber, the businesses that get tagged are the ones with active, professional Facebook profiles. If your profile is outdated, incomplete, or nonexistent, you are invisible in the most powerful recommendation channel in the town."}, {"title": "Unprofessional social profiles deterring Sittingbourne customers", "description": "A potential customer sees your business recommended in a Sittingbourne Facebook group and clicks through to your page. They find a blurry logo, no cover image, outdated contact information, and the last post was six months ago. They move on to the next recommendation. Your social profile just cost you a customer."}, {"title": "No social strategy for the platforms Sittingbourne actually uses", "description": "Posting randomly across multiple platforms without understanding where your Sittingbourne customers actually engage wastes time. A trade business investing in TikTok while ignoring Facebook community groups is missing the channel that generates actual work in this market."}]',
  '[{"title": "Facebook setup optimised for Sittingbourne community engagement", "description": "We create professional Facebook business profiles designed for the way Sittingbourne residents actually discover businesses. Optimised for community group visibility, complete with professional imagery, accurate service descriptions, and review prompts that build social proof within the local community."}, {"title": "Multi-platform presence matching your Sittingbourne audience", "description": "Beyond Facebook, we set up the platforms that matter for your specific Sittingbourne business. Instagram for hospitality and retail near The Forum. LinkedIn for Eurolink commercial businesses. Google Business Profile integrated with your social strategy. Every platform is set up professionally with consistent branding."}, {"title": "Content framework for consistent Sittingbourne social posting", "description": "We deliver a practical content framework with post templates, content categories, and a scheduling strategy that your team can execute independently. Local content hooks from Milton Creek Country Park to Sittingbourne town events keep your posting relevant and authentic to the community."}]',
  '[{"question": "Which social media platforms matter most for Sittingbourne businesses?", "answer": "Facebook is essential for almost all Sittingbourne businesses because of the active community groups where residents seek recommendations. Instagram is increasingly important for hospitality and retail. LinkedIn matters for commercial and industrial businesses at Eurolink. We recommend the right mix based on your specific audience."}, {"question": "Can you help me engage with Sittingbourne Facebook groups?", "answer": "We set up your profile to be community-group ready, with the information and visual assets that make a strong impression when you are tagged or mentioned. We also provide guidelines for engaging authentically in these groups. Building reputation in Sittingbourne community groups requires genuine participation that we can coach you on."}, {"question": "How long does social media setup take?", "answer": "A complete multi-platform setup typically takes one to two weeks. This includes platform selection, professional visual asset creation, complete profile optimisation with accurate business information, and development of a practical content framework your team can follow."}, {"question": "Do you manage social media after setting it up?", "answer": "Our core service is professional setup and strategy. We deliver fully optimised profiles with content templates and scheduling guidance. If you want ongoing management, we can discuss retainer options. Many Sittingbourne businesses find the framework sufficient to maintain a strong presence independently."}]',
  'trust'
)
